const authScript=`<script type="module" id="bare-auth-review-script">import{createClient}from'https://cdn.jsdelivr.net/npm/@supabase/supabase-js/+esm';const cfg=window.BARE_SUPABASE_CONFIG||{};const supabase=createClient(cfg.url,cfg.key);let user=null,mode='login';const modal=document.querySelector('.member-modal'),trigger=document.querySelector('.member-trigger'),form=document.querySelector('.member-form'),note=document.querySelector('.member-form .member-note'),userBox=document.querySelector('.member-user'),userNote=document.querySelector('.member-user .member-note'),logoutBtn=document.querySelector('.member-logout'),tabs=document.querySelectorAll('[data-member-mode]');function openModal(){modal?.classList.add('is-open');modal?.setAttribute('aria-hidden','false')}function closeModal(){modal?.classList.remove('is-open');modal?.setAttribute('aria-hidden','true')}function setNote(text){if(note)note.textContent=text}function syncUser(next){user=next;trigger&&(trigger.textContent=user?'ACCOUNT':'LOGIN');if(user){form&&(form.style.display='none');userBox?.classList.add('is-open');userNote&&(userNote.textContent=(user.email||'BARE. member')+' 로 로그인 중입니다.');window.dispatchEvent(new CustomEvent('bare-account-sync'))}else{form&&(form.style.display='grid');userBox?.classList.remove('is-open')}}trigger?.addEventListener('click',openModal);modal?.querySelector('.member-close')?.addEventListener('click',closeModal);modal?.addEventListener('click',e=>{if(e.target===modal)closeModal()});tabs.forEach(btn=>btn.addEventListener('click',()=>{mode=btn.dataset.memberMode;tabs.forEach(item=>item.classList.toggle('is-active',item===btn));document.querySelector('.member-submit').textContent=mode==='signup'?'SIGN UP':'LOGIN';setNote(mode==='signup'?'가입 후 이메일 인증이 필요할 수 있습니다.':'이메일과 비밀번호로 로그인해주세요.')}));form?.addEventListener('submit',async e=>{e.preventDefault();const fd=new FormData(form),email=String(fd.get('email')||'').trim(),password=String(fd.get('password')||'');try{const result=mode==='signup'?await supabase.auth.signUp({email,password,options:{emailRedirectTo:location.origin}}):await supabase.auth.signInWithPassword({email,password});if(result.error)throw result.error;if(mode==='signup'&&!result.data.session){setNote('가입 메일을 보냈어요. 이메일 인증 후 로그인해주세요.');return}syncUser(result.data.user);closeModal()}catch(err){setNote(err.message||'회원 처리 중 문제가 생겼습니다.')}});logoutBtn?.addEventListener('click',async()=>{await supabase.auth.signOut();syncUser(null)});supabase.auth.onAuthStateChange((_event,session)=>syncUser(session?.user||null));const{data}=await supabase.auth.getUser();syncUser(data.user||null);</script>`;
const accountScript=`<script id="bare-account-panel-script">(()=>{const cartKey='bare_cart_items',orderKey='bare_order_items',checkoutKey='bare_checkout_items',checkoutUrl='/order/orderform.html?basket_type=A0000&delvtype=A',loginUrl='/member/login.html';const money=value=>'₩'+Number(value||0).toLocaleString('ko-KR');const read=key=>{try{return JSON.parse(localStorage.getItem(key)||'[]')}catch{return[]}};const write=(key,value)=>localStorage.setItem(key,JSON.stringify(value));function goCheckout(items){write(checkoutKey,items.filter(Boolean));location.href=loginUrl+'?returnUrl='+encodeURIComponent(checkoutUrl)}function itemMarkup(item,index,kind){return '<article class="account-item"><img src="'+(item.image||'')+'" alt=""><div><p class="account-item-title">'+(item.title||'BARE. product')+'</p><p class="account-item-meta">'+(item.option||'옵션 선택 내역 없음')+'</p><p class="account-item-meta">'+new Date(item.createdAt||Date.now()).toLocaleDateString('ko-KR')+'</p></div><strong class="account-item-price">'+money(item.price)+'</strong>'+(kind==='cart'?'<button class="account-buy" type="button" data-cart-buy="'+index+'">BUY THIS ITEM</button>':'')+'</article>'}function ensureDashboard(){const box=document.querySelector('.member-user');if(!box||box.querySelector('.member-dashboard'))return;const note=box.querySelector('.member-note'),logout=box.querySelector('.member-logout');box.insertAdjacentHTML('afterbegin','<div class="member-dashboard"><div class="account-head"><div><p class="account-name"></p><p class="account-email"></p></div></div><div class="account-tabs"><button class="account-tab is-active" type="button" data-account-tab="orders">ORDER</button><button class="account-tab" type="button" data-account-tab="cart">CART</button></div><section class="account-panel is-active" data-account-panel="orders"><div class="account-list"></div></section><section class="account-panel" data-account-panel="cart"><div class="account-list"></div></section></div>');note?.remove();box.appendChild(logout);box.querySelectorAll('[data-account-tab]').forEach(btn=>btn.addEventListener('click',()=>{box.querySelectorAll('[data-account-tab]').forEach(tab=>tab.classList.toggle('is-active',tab===btn));box.querySelectorAll('[data-account-panel]').forEach(panel=>panel.classList.toggle('is-active',panel.dataset.accountPanel===btn.dataset.accountTab))}));box.addEventListener('click',event=>{const buy=event.target.closest('[data-cart-buy]');if(!buy)return;const item=read(cartKey)[Number(buy.dataset.cartBuy)];if(item)goCheckout([item])});renderAccount()}function renderAccount(){const box=document.querySelector('.member-user');if(!box)return;ensureDashboard();const name=(box.querySelector('.member-note')?.textContent||'').replace(' 로 로그인 중입니다.','')||'BARE. Member';box.querySelector('.account-name')&&(box.querySelector('.account-name').textContent=name);box.querySelector('.account-email')&&(box.querySelector('.account-email').textContent='비회원 구매도 로그인 없이 이용할 수 있습니다.');const orders=read(orderKey),cart=read(cartKey),orderList=box.querySelector('[data-account-panel="orders"] .account-list'),cartList=box.querySelector('[data-account-panel="cart"] .account-list');if(orderList)orderList.innerHTML=orders.length?orders.map((item,index)=>itemMarkup(item,index,'order')).join(''):'<p class="account-empty">아직 주문 내역이 없습니다.<br>스마트스토어 결제 완료 내역은 결제 연동 후 자동 표시됩니다.</p>';if(cartList)cartList.innerHTML=cart.length?cart.map((item,index)=>itemMarkup(item,index,'cart')).join(''):'<p class="account-empty">장바구니에 담긴 상품이 없습니다.<br>상품 상세에서 사이즈를 선택한 뒤 ADD TO CART를 눌러주세요.</p>'}function selectedOptionText(){return [...document.querySelectorAll('.option-block')].map(group=>{const label=group.querySelector('label')?.textContent?.trim()||'SIZE',size=group.querySelector('.size-button.is-selected')?.dataset.size;return size?label+': '+size:null}).filter(Boolean).join(' / ')}function detailItem(){if(typeof activeProduct==='undefined')return null;const option=selectedOptionText();if(!option)return null;return{title:activeProduct.title,price:typeof currentDetailPrice==='function'?currentDetailPrice():activeProduct.price,image:activeProduct.main,option,createdAt:Date.now()}}function ensureShopActions(){const total=document.querySelector('.total-row');if(!total||document.querySelector('.member-shop-actions'))return;total.insertAdjacentHTML('afterend','<div class="member-shop-actions"><button class="add-cart" type="button">ADD TO CART</button><button class="guest-buy" type="button">BUY NOW</button></div><p class="member-action-note">로그인하지 않아도 장바구니와 비회원 주문서를 사용할 수 있습니다.</p>');document.querySelector('.add-cart')?.addEventListener('click',()=>{const item=detailItem();if(!item){alert('사이즈를 먼저 선택해주세요.');return}const cart=read(cartKey);cart.unshift(item);write(cartKey,cart.slice(0,20));renderAccount();alert('장바구니에 담았습니다. ACCOUNT에서 확인할 수 있어요.')});document.querySelector('.guest-buy')?.addEventListener('click',()=>{const item=detailItem();if(!item){alert('사이즈를 먼저 선택해주세요.');return}goCheckout([item])})}document.addEventListener('click',event=>{if(event.target.closest('.member-trigger'))setTimeout(renderAccount,80);if(event.target.closest('.size-button'))setTimeout(ensureShopActions,80)});addEventListener('bare-account-sync',()=>setTimeout(renderAccount,80));addEventListener('hashchange',()=>setTimeout(ensureShopActions,120));ensureShopActions();renderAccount()})();</script>`;
function patchHtml(html){const headerPattern=/<header class="topbar" aria-label="BAREDOT navigation">[\s\S]*?<\/header>/;let patched=html.replace('<meta name="viewport" content="width=device-width, initial-scale=1">','<meta name="viewport" content="width=device-width, initial-scale=1">'+bareIntroHeadScript).replace(/<section class="hero"[\s\S]*?<\/section>/,'<section class="hero" aria-label="BARE. hero video"><video class="hero-video" autoplay muted loop playsinline webkit-playsinline preload="metadata" poster="https://shop-phinf.pstatic.net/20260510_80/1778395793811MbSLH_JPEG/112528597587931990_1106622545.jpg?type=o1000"><source src="assets/hero-comp-1-21.mp4" type="video/mp4"></video></section>').replace(/<script>function ensureHeroVideo\(\)[\s\S]*?<\/script>/,'').replace(/<style id="fix-hero-full-final">[\s\S]*?<\/style>/g,'').replace(/<style id="fix-mens-soon-final">[\s\S]*?<\/style>/g,'').replace(/<script id="fix-mens-soon-typing">[\s\S]*?<\/script>/g,'').replace(/\.collection-empty\.is-visible\{animation:men-soon-type-short 3\.4s steps\(5,end\) infinite!important\}@keyframes men-soon-type-short\{0%,12%\{width:0\}48%,72%\{width:5ch\}100%\{width:0\}\}/g,'').replace(/assets\/hero-original-web\.mp4/g,'assets/hero-comp-1-21.mp4').replace(/<style id="codex-deploy-menu-promo">[\s\S]*?<\/style>/,'').replace(/<style id="bare-auth-review-style">[\s\S]*?<\/style>/,'').replace(/<script id="bare-account-panel-script">[\s\S]*?<\/script>/,'').replace(/<script id="bare-firebase-config">[\s\S]*?<\/script>/,'').replace(/<script id="bare-supabase-config">[\s\S]*?<\/script>/,'').replace(/<script type="module" id="bare-auth-review-script">[\s\S]*?<\/script>/,'').replace(/<aside class="member-modal"[\s\S]*?<\/aside>/,'');patched=patched.replace('</head>',menuStyle+'\n'+authStyle+'\n'+mensSoonStyle+'\n'+bareBuyInstructorStyle+'\n'+detailBuyBarStyle+'\n'+heroFullStyle+'\n'+sandollFontStyle+'\n</head>');patched=patched.replace(headerPattern,menuHeader);patched=patched.replace(/<nav class="footer-links" aria-label="Footer information">[\s\S]*?<\/nav>/,footerLinks);return patched.replace('</body>',memberMarkup+'\n'+supabaseConfig+'\n'+authScript+'\n'+accountScript+'\n'+mensSoonScript+'\n'+instructorMarkup+'\n'+bareBuyInstructorScript+'\n</body>')}
export default{async fetch(request,env){const url=new URL(request.url);if(url.pathname==='/api/toss/confirm')return confirmTossPayment(request,env);if(url.pathname==='/api/auth/kakao')return startSocialAuth(request,env,'kakao');if(url.pathname==='/api/auth/naver')return startSocialAuth(request,env,'naver');if(url.pathname==='/api/auth/kakao/callback')return handleSocialCallback(request,env,'kakao');if(url.pathname==='/api/auth/naver/callback')return handleSocialCallback(request,env,'naver');if(url.pathname==='/about.html'||url.pathname==='/about')return new Response(aboutPage,{headers:{'content-type':'text/html;charset=utf-8','cache-control':'no-cache'}});if(url.pathname==='/member/login.html'||url.pathname==='/member/login'||url.pathname==='/login')return new Response(simpleLoginPage(),{headers:{'content-type':'text/html;charset=utf-8','cache-control':'no-cache'}});if(url.pathname==='/order/orderform.html'||url.pathname==='/order/orderform')return new Response(modernCheckoutPage(),{headers:{'content-type':'text/html;charset=utf-8','cache-control':'no-cache'}});if(url.pathname==='/order/success')return new Response(tossSuccessPage,{headers:{'content-type':'text/html;charset=utf-8','cache-control':'no-cache'}});if(url.pathname==='/order/fail')return new Response(tossFailPage,{headers:{'content-type':'text/html;charset=utf-8','cache-control':'no-cache'}});const response=await env.ASSETS.fetch(request);const type=response.headers.get('content-type')||'';if(!type.includes('text/html'))return response;const headers=new Headers(response.headers);headers.delete('content-length');headers.set('cache-control','no-cache');return new Response(patchHtml(await response.text()),{status:response.status,statusText:response.statusText,headers})}};

